"use strict";(globalThis.webpackChunkdocusaurus_resource=globalThis.webpackChunkdocusaurus_resource||[]).push([[6608],{4958:e=>{e.exports=JSON.parse('{"tag":{"label":"level/intermediate","permalink":"/accessibility-hub/docs/tags/level-intermediate","allTagsPath":"/accessibility-hub/docs/tags","count":8,"items":[{"id":"for-developers/apis-sdks","title":"Accessibility APIs & SDKs","description":"APIs and SDKs for accessibility development. (Content to be expanded based on future contributions and curation.)","permalink":"/accessibility-hub/docs/for-developers/apis-sdks"},{"id":"for-developers/accessible-api-design-guide","title":"Accessible API Design for Developers","description":"Accessibility in software is often associated with user interfaces, but it is equally important in API and schema design. Accessible APIs improve usability for developers using assistive technologies, enhance code readability, and support better tooling integration. This guide outlines key strategies Java developers can adopt to make their APIs more inclusive.","permalink":"/accessibility-hub/docs/for-developers/accessible-api-design-guide"},{"id":"resources/learning-paths/certifications","title":"Certifications","description":"Validate your expertise with these industry-recognized certifications.","permalink":"/accessibility-hub/docs/resources/learning-paths/certifications"},{"id":"resources/conferences-events","title":"Conferences & Events","description":"Stay current and network with peers at these key events. Many offer free virtual attendance or post recordings online.","permalink":"/accessibility-hub/docs/resources/conferences-events"},{"id":"community-contributions/contributing","title":"Contributing to the Accessibility Hub","description":"Thank you for your interest in contributing to our Accessibility Hub!","permalink":"/accessibility-hub/docs/community-contributions/contributing"},{"id":"for-developers/case-studies","title":"Developer Case Studies","description":"Case studies for developers working on accessibility. (Content to be expanded based on future contributions and curation.)","permalink":"/accessibility-hub/docs/for-developers/case-studies"},{"id":"for-developers/engineering-gaps","title":"Engineering Gaps & Design Patterns","description":"| Challenge                               | Opportunity                            | Suggested Tech         |","permalink":"/accessibility-hub/docs/for-developers/engineering-gaps"},{"id":"unmet-needs/unmet-needs","title":"Unmet Needs & Future Possibilities","description":"- Advanced reading workflows for scientists (skimming, referencing, jumping between sections). Currently, OCR and screen readers are limited to reading text in graphs. True accessibility for statistical graphs requires authors to include descriptive text and, ideally, provide underlying data in accessible formats. AI solutions for automatic graph interpretation are in early stages and not yet reliable for critical scientific content.","permalink":"/accessibility-hub/docs/unmet-needs/unmet-needs"}],"unlisted":false}}')}}]);